          scientificExplanation: { type: Type.STRING, description: "Spiegazione tecnica/contabile (non allarmistica) del perché potrebbe esserci questo disallineamento. Cita arrotondamenti, voci figurative, ecc." },
        },
        required: ["isConsistent", "message", "severity"],
      },
    },
