      type: Type.OBJECT,
      properties: {
        summary: { type: Type.STRING },
        keyTakeaways: {
          type: Type.ARRAY,
          items: { type: Type.STRING },
        },
      },
      required: ["summary", "keyTakeaways"],
    },
    finalSummary: {
      type: Type.OBJECT,
      properties: {
        netTotal: { type: Type.STRING },
        grossTotal: { type: Type.STRING },
        topImpactItems: {
          type: Type.ARRAY,
          items: { type: Type.STRING },
        },
        improvementTips: { type: Type.STRING },
      },
      required: ["netTotal", "grossTotal", "topImpactItems", "improvementTips"],
    },
  },
  required: ["generalData", "leaveAnalysis", "lineItems", "calculations", "consistencyChecks", "simpleExplanation", "finalSummary"],
};

import { GoogleGenAI } from "@google/genai";
import { ANALYSIS_SCHEMA, PAYSLIP_ANALYSIS_PROMPT } from "../constants";
import { AnalysisResult } from "../types";

export const analyzePayslipWithGemini = async (pdfText: string): Promise<AnalysisResult> => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key mancante.");
  }

  const ai = new GoogleGenAI({ apiKey });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: [
        {
            role: 'user',
            parts: [
                { text: PAYSLIP_ANALYSIS_PROMPT },
                { text: `Ecco il contenuto estratto dal PDF della busta paga:\n\n${pdfText}` }
            ]
        }
      ],
      config: {
        responseMimeType: "application/json",
        responseSchema: ANALYSIS_SCHEMA,
        temperature: 0.2, // Low temperature for factual consistency
      },
    });

    let textResponse = response.text;
    if (!textResponse) {
        throw new Error("Risposta vuota da Gemini.");
    }

    // Sanitize Markdown code blocks if present (common cause of JSON.parse errors)
    // Gemini sometimes wraps the JSON in ```json ... ``` despite responseMimeType
    if (textResponse.trim().startsWith("```")) {
       textResponse = textResponse.replace(/^```json\s*/, "").replace(/^```\s*/, "").replace(/\s*```$/, "");
    }

    const jsonResponse = JSON.parse(textResponse) as AnalysisResult;
    return jsonResponse;

  } catch (error) {
    console.error("Gemini Analysis Error:", error);
    throw new Error("Errore durante l'analisi AI della busta paga. Verifica che il documento sia leggibile.");
  }
};

